using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Web.Mvc;
using System.Web.Mvc.Html;
using System.Text.RegularExpressions;

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string UserName { get; set; }
    public string Content { get; set; }
    public DateTime CreatedDate { get; set; }
    public int Rating { get; set; }
}

public class ProductReviewController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductReviewController()
    {
        _context = new ApplicationDbContext();
    }

    public ActionResult Index(int productId)
    {
        var reviews = _context.Reviews
            .Where(r => r.ProductId == productId)
            .OrderByDescending(r => r.CreatedDate)
            .ToList();

        var viewModel = new ProductReviewViewModel
        {
            ProductId = productId,
            Reviews = reviews
        };

        return View(viewModel);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult Create(Review review)
    {
        if (ModelState.IsValid)
        {
            review.Content = SanitizeHtml(review.Content);
            review.CreatedDate = DateTime.Now;
            _context.Reviews.Add(review);
            _context.SaveChanges();
            return RedirectToAction("Index", new { productId = review.ProductId });
        }

        return RedirectToAction("Index", new { productId = review.ProductId });
    }

    private string SanitizeHtml(string input)
    {
        if (string.IsNullOrEmpty(input))
            return input;

        // Allow only basic formatting tags
        var allowedTags = new[] { "b", "i", "u" };
        var sanitized = input;

        // Remove script tags and other dangerous elements
        sanitized = Regex.Replace(sanitized, "<script[^>]*>.*?</script>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);
        sanitized = Regex.Replace(sanitized, "<iframe[^>]*>.*?</iframe>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);
        sanitized = Regex.Replace(sanitized, "<object[^>]*>.*?</object>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);
        sanitized = Regex.Replace(sanitized, "<embed[^>]*>.*?</embed>", "", RegexOptions.IgnoreCase | RegexOptions.Singleline);

        // Allow only specific tags
        foreach (var tag in allowedTags)
        {
            sanitized = Regex.Replace(sanitized, $"<{tag}([^>]*)>", $"<{tag}>", RegexOptions.IgnoreCase);
            sanitized = Regex.Replace(sanitized, $"</{tag}>", $"</{tag}>", RegexOptions.IgnoreCase);
        }

        // Remove all other tags
        sanitized = Regex.Replace(sanitized, "<[^>]*>", "", RegexOptions.IgnoreCase);

        return sanitized;
    }
}

